const content = ($json.text || $json.output || $json.response || $json.message || $json.data?.text || "{}").toString();

function cleanAndParse(str) {
  if (!str || str.trim() === "{}") return {};

  // 1. Basic JSON parse
  try { return JSON.parse(str); } catch (e) {}

  // 2. Try to find the JSON block via first { and last }
  const start = str.indexOf('{');
  const end = str.lastIndexOf('}');
  if (start === -1 || end === -1 || end < start) return {};
  let jsonStr = str.substring(start, end + 1);

  // 3. Clean common LLM mistakes
  try { return JSON.parse(jsonStr); } catch (e) {
    jsonStr = jsonStr
      .replace(/\/\/.*$/gm, '') // Remove single line comments
      .replace(/\/\*[\s\S]*?\*\//g, '') // Remove multi line comments
      .replace(/,\s*([}\]])/g, '$1') // Remove trailing commas
      .replace(/[\x00-\x1F\x7F-\x9F]/g, ""); // Remove control characters and non-printable

    try { return JSON.parse(jsonStr); } catch (e2) {
      // Last resort: try to fix unescaped newlines in strings
      try {
         const fixed = jsonStr.replace(/:\s*"([\s\S]*?)"/g, (m, p1) => {
           return ': "' + p1.replace(/\n/g, '\\n').replace(/\r/g, '\\r') + '"';
         });
         return JSON.parse(fixed);
      } catch (e3) {
         return {}; // Give up
      }
    }
  }
}

const parsed = cleanAndParse(content);
return [{ json: { ...$json, analysis: parsed } }];

function pad(n){return n.toString().padStart(2,'0');}
const now = new Date();
const ts = `${now.getFullYear()}${pad(now.getMonth()+1)}${pad(now.getDate())}_${pad(now.getHours())}${pad(now.getMinutes())}${pad(now.getSeconds())}`;

// Redundant access to analysis data for maximum compatibility
let analysis = {};
try { analysis = $('Parse Analysis').first().json.analysis || {}; } catch (e) {
  try { analysis = $node["Parse Analysis"].json.analysis || {}; } catch (e2) { analysis = {}; }
}

const title = (analysis.job_title || 'job').toString();
const company = (analysis.company || 'company').toString();
const safe = s => s.replace(/[^a-zA-Z0-9]+/g,'_').replace(/^_+|_+$/g,'').toLowerCase();
const base = `${ts}__${safe(title)}__${safe(company)}`;
const webhookBase = ($env.WEBHOOK_URL || '').replace(/\/+$/,'') + '/';
const token = $env.CV_DOWNLOAD_TOKEN || '';
const finalCv = $node["Review CV"].json.text || $node["Review CV"].json.output || $node["Review CV"].json.response || $node["Review CV"].json.message || '';
const cover = $node["Generate Cover Letter"].json.text || $node["Generate Cover Letter"].json.output || $node["Generate Cover Letter"].json.response || $node["Generate Cover Letter"].json.message || '';
return [{
  ...$json,
  ts,
  cv_filename: `${base}.docx`,
  cover_filename: `${base}_cover.docx`,
  cv_markdown: finalCv,
  cover_markdown: cover,
  cv_download_url: `${webhookBase}webhook/cv-download?file=${encodeURIComponent(`${base}.docx`)}&token=${token}`,
  cover_download_url: `${webhookBase}webhook/cv-download?file=${encodeURIComponent(`${base}_cover.docx`)}&token=${token}`
}];

const fs = require('fs');
const path = '/cvdata/generated_cv/' + $json.cv_filename.replace('.docx', '.md');
fs.mkdirSync('/cvdata/generated_cv', { recursive: true });
fs.writeFileSync(path, $json.cv_markdown, 'utf8');
return [$input.item];

