fs.mkdirSync('/cvdata/generated_cv', { recursive: true });
fs.writeFileSync(path, $json.cover_markdown, 'utf8');
return [$input.item];

const html = $json.body || $json.data || $json || '';
const text = typeof html === 'string' ? html : '';
let posting = null;

// 1) Try JSON-LD JobPosting
const regex = /<script[^>]*type=["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script>/gi;
let match;
while ((match = regex.exec(text)) !== null) {
  const raw = match[1].trim();
  try {
    const obj = JSON.parse(raw);
    if (obj['@type'] === 'JobPosting') { posting = obj; break; }
  } catch (e) {}
}

// 2) Fallback: parse Next.js data
let description = posting?.description || '';
if (!description) {
  const nextMatch = text.match(/<script[^>]*id=["']__NEXT_DATA__["'][^>]*>([\s\S]*?)<\/script>/i);
  if (nextMatch) {
    try {
      const nextData = JSON.parse(nextMatch[1]);
      description = nextData?.props?.pageProps?.consolidatedJobDetails?.jobDetails?.description || '';
    } catch (e) {}
  }
}

return [{ clean_job_description: description }];

